import logging
import logging.handlers
import os

# Define the log directory and ensure it exists
LOG_DIR = '/var/log/application'
os.makedirs(LOG_DIR, exist_ok=True)

# Define log file paths
APP_LOG_FILE = os.path.join(LOG_DIR, 'application.log')
ERROR_LOG_FILE = os.path.join(LOG_DIR, 'application_error.log')

# Define log formatters
# Standard format for application logs
STANDARD_FORMATTER = logging.Formatter(
    '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
# Detailed format for debugging or specific needs (can be adjusted)
DETAILED_FORMATTER = logging.Formatter(
    '%(asctime)s - %(name)s - %(levelname)s - %(filename)s:%(lineno)d - %(funcName)s - %(message)s'
)

def configure_logging():
    """
    Configures the application's logging system for production.
    Logs are written to files with rotation and specific formatting.
    """
    # Get the root logger
    root_logger = logging.getLogger()
    root_logger.setLevel(logging.INFO) # Default level for the root logger

    # Clear existing handlers to prevent duplicate logs if called multiple times
    if root_logger.hasHandlers():
        root_logger.handlers.clear()

    # --- Handler for all application logs (INFO and above) ---
    # Rotates logs daily, keeps 7 backup files
    app_file_handler = logging.handlers.TimedRotatingFileHandler(
        APP_LOG_FILE,
        when='midnight',
        interval=1,
        backupCount=7,
        encoding='utf-8'
    )
    app_file_handler.setLevel(logging.INFO)
    app_file_handler.setFormatter(STANDARD_FORMATTER)
    root_logger.addHandler(app_file_handler)

    # --- Handler for ERROR and CRITICAL logs ---
    # Rotates logs daily, keeps 7 backup files
    error_file_handler = logging.handlers.TimedRotatingFileHandler(
        ERROR_LOG_FILE,
        when='midnight',
        interval=1,
        backupCount=7,
        encoding='utf-8'
    )
    error_file_handler.setLevel(logging.ERROR) # Only logs ERROR and CRITICAL
    error_file_handler.setFormatter(DETAILED_FORMATTER) # Use a more detailed format for errors
    root_logger.addHandler(error_file_handler)

    # Optional: Add a console handler for development/testing if needed,
    # but typically removed or set to a higher level in production.
    # For production, we usually rely solely on file handlers.
    # console_handler = logging.StreamHandler()
    # console_handler.setLevel(logging.DEBUG)
    # console_handler.setFormatter(STANDARD_FORMATTER)
    # root_logger.addHandler(console_handler)

    logging.info("Logging configured successfully for production environment.")

if __name__ == '__main__':
    configure_logging()

